+}
+
+if (!sawWorkMarker) {
+  throw new Error("Built bundle must retain the service-worker-broker-work marker");
+}
+
+if (!sawHandoffMarker) {
+  throw new Error("Built bundle must retain the service-worker-broker-handoff marker");
+}
+
+if (!sawReopenMarker) {
